// Service class to generate and store backup codes
@Service
public class BackupCodeService {

    @Autowired
    private UserRepository userRepository;

    public void generateBackupCodes(User user) {
        List<String> codes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            codes.add(UUID.randomUUID().toString().substring(0, 6));
        }
        user.setBackupCodes(codes);
        userRepository.save(user);
    }
}

// Controller class to handle user authentication using backup codes
@RestController
public class AuthenticationController {

    @Autowired
    private UserRepository userRepository;

    @PostMapping("/authenticate/backup-code")
    public ResponseEntity<String> authenticateByBackupCode(@RequestParam String username, @RequestParam String code) {
        User user = userRepository.findByUsername(username);
        if (user.getBackupCodes().contains(code)) {
            // Perform authentication logic here
            return ResponseEntity.ok("Authenticated successfully.");
        } else {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid backup code.");
        }
    }
}

